syntax.mysql:
-- Hash indexes are only available in MEMORY tables
CREATE TABLE session_cache (
  session_id VARCHAR(64) PRIMARY KEY,
  user_id INT NOT NULL,
  INDEX idx_user_hash (user_id) USING HASH
) ENGINE=MEMORY;

syntax.mariadb:
-- Hash indexes are only available in MEMORY/Aria tables
CREATE TABLE session_cache (
  session_id VARCHAR(64) PRIMARY KEY,
  user_id INT NOT NULL,
  INDEX idx_user_hash (user_id) USING HASH
) ENGINE=MEMORY;

syntax.postgresql:
-- GIN index on JSONB column
CREATE INDEX idx_products_attrs ON products USING GIN (attributes);

-- GIN index for full-text search
CREATE INDEX idx_products_search ON products USING GIN (to_tsvector('english', name || ' ' || description));

-- GIN index on array column
CREATE INDEX idx_products_tags ON products USING GIN (tags);

-- GiST index for range overlap queries
CREATE INDEX idx_bookings_during ON bookings USING GIST (during);

-- GiST index for geometric data
CREATE INDEX idx_locations_point ON locations USING GIST (coordinates);

-- GiST index for full-text search
CREATE INDEX idx_products_fts ON products USING GIST (to_tsvector('english', name));

-- SP-GiST index on inet (IP address) column
CREATE INDEX idx_access_log_ip ON access_log USING SPGIST (client_ip);

-- SP-GiST index on text for prefix searches
CREATE INDEX idx_users_phone ON users USING SPGIST (phone);

-- BRIN index on a timestamp column (ideal for time-series data)
CREATE INDEX idx_events_created ON events USING BRIN (created_at);

-- BRIN with custom pages_per_range
CREATE INDEX idx_logs_timestamp ON access_logs USING BRIN (logged_at) WITH (pages_per_range = 32);

-- Create a tsvector column and GIN index for full-text search
ALTER TABLE products ADD COLUMN search_vector TSVECTOR;

UPDATE products SET search_vector = to_tsvector('english', name || ' ' || COALESCE(description, ''));

CREATE INDEX idx_products_fts ON products USING GIN (search_vector);

-- Query
SELECT name FROM products
WHERE search_vector @@ to_tsquery('english', 'wireless & keyboard');

syntax.mysql:
-- Create a fulltext index
ALTER TABLE products ADD FULLTEXT INDEX idx_products_fts (name, description);

-- Query using natural language mode
SELECT name FROM products
WHERE MATCH(name, description) AGAINST ('wireless keyboard' IN NATURAL LANGUAGE MODE);

syntax.mariadb:
-- Create a fulltext index
ALTER TABLE products ADD FULLTEXT INDEX idx_products_fts (name, description);

-- Query using natural language mode
SELECT name FROM products
WHERE MATCH(name, description) AGAINST ('wireless keyboard' IN NATURAL LANGUAGE MODE);

syntax.sqlite:
-- Create a FTS5 virtual table
CREATE VIRTUAL TABLE products_fts USING fts5(
  name,
  description,
  content=products,
  content_rowid=id
);

-- Query
SELECT name FROM products_fts WHERE products_fts MATCH 'wireless keyboard';

syntax.postgresql:
-- Using PostGIS extension
CREATE EXTENSION IF NOT EXISTS postgis;

CREATE TABLE locations (
  id SERIAL PRIMARY KEY,
  name VARCHAR(100) NOT NULL,
  geom GEOMETRY(Point, 4326) NOT NULL
);

CREATE INDEX idx_locations_geom ON locations USING GIST (geom);

-- Find locations within 1km of a point
SELECT name FROM locations
WHERE ST_DWithin(geom, ST_SetSRID(ST_MakePoint(127.0, 37.5), 4326), 1000);

syntax.mysql:
CREATE TABLE locations (
  id INT AUTO_INCREMENT PRIMARY KEY,
  name VARCHAR(100) NOT NULL,
  coordinates POINT NOT NULL SRID 4326,
  SPATIAL INDEX idx_locations_coords (coordinates)
);

-- Find locations within a bounding box
SELECT name FROM locations
WHERE MBRContains(
  ST_GeomFromText('POLYGON((126.9 37.4, 127.1 37.4, 127.1 37.6, 126.9 37.6, 126.9 37.4))'),
  coordinates
);

syntax.mariadb:
CREATE TABLE locations (
  id INT AUTO_INCREMENT PRIMARY KEY,
  name VARCHAR(100) NOT NULL,
  coordinates POINT NOT NULL,
  SPATIAL INDEX idx_locations_coords (coordinates)
