  coordinates
);

syntax.sqlite:
-- Using R*Tree extension
CREATE VIRTUAL TABLE locations_idx USING rtree(
  id,
  min_lat, max_lat,
  min_lon, max_lon
);

syntax.postgresql:
-- Index only active users
CREATE INDEX idx_users_active_email ON users(email)
  WHERE status = 'active';

-- Index only unpaid orders
CREATE INDEX idx_orders_unpaid ON orders(created_at)
  WHERE is_paid = FALSE;

syntax.sqlite:
-- SQLite supports partial indexes
CREATE INDEX idx_users_active_email ON users(email)
  WHERE status = 'active';

CREATE INDEX idx_orders_unpaid ON orders(created_at)
  WHERE is_paid = 0;

syntax.postgresql:
-- Case-insensitive email lookup
CREATE INDEX idx_users_email_lower ON users(LOWER(email));

-- Index on year extracted from timestamp
CREATE INDEX idx_orders_year ON orders(EXTRACT(YEAR FROM created_at));

-- Query that uses the index
SELECT * FROM users WHERE LOWER(email) = 'john@example.com';

syntax.mysql:
-- Expression index (MySQL 8.0+)
CREATE INDEX idx_users_email_lower ON users((LOWER(email)));

-- Index on year extracted from date
CREATE INDEX idx_orders_year ON orders((YEAR(created_at)));

-- Query that uses the index
SELECT * FROM users WHERE LOWER(email) = 'john@example.com';

syntax.mariadb:
-- Expression index (MariaDB 10.2+)
CREATE INDEX idx_users_email_lower ON users((LOWER(email)));

-- Index on year extracted from date
CREATE INDEX idx_orders_year ON orders((YEAR(created_at)));

-- Query that uses the index
SELECT * FROM users WHERE LOWER(email) = 'john@example.com';

syntax.sqlite:
