syntax.postgresql:
-- Covering index using INCLUDE clause
CREATE INDEX idx_orders_user_covering ON orders(user_id)
  INCLUDE (status, total, created_at);

-- The query below can be answered using the index alone
-- SELECT status, total, created_at FROM orders WHERE user_id = 42;

syntax.mysql:
-- Covering index (multi-column index that covers the query)
CREATE INDEX idx_orders_user_covering ON orders(user_id, status, total, created_at);

-- The query below can be answered using the index alone
-- SELECT status, total, created_at FROM orders WHERE user_id = 42;

syntax.mariadb:
-- Covering index (multi-column index that covers the query)
CREATE INDEX idx_orders_user_covering ON orders(user_id, status, total, created_at);

-- The query below can be answered using the index alone
-- SELECT status, total, created_at FROM orders WHERE user_id = 42;

syntax.sqlite:
-- Covering index (multi-column index)
CREATE INDEX idx_orders_user_covering ON orders(user_id, status, total, created_at);

